    @Override
    @InitializeAdmin
    public List<RmControleLijstItem> getControleLijst(Admin admin, Integer bNummer, List<Integer> opdrachtIdList) {
        List<RekenHoofd> result = vindRekenResultatenMetBnr(admin, bNummer, opdrachtIdList);
        LoonBeslagData loonBeslagData = bouwLoonBeslagData(admin, result);
        List<RmControleLijstItem> controles = controlesOpBrutoNetto(result);
        controles.addAll(controlesBlo(result, loonBeslagData));
        controles.addAll(controleAanwezigheidJaarVergoeding(result));
        return controles;
    }

    private List<RmControleLijstItem> controleAanwezigheidJaarVergoeding(List<RekenHoofd> result) {
        Multimap<Persoon, String> persoonToJaarVergoedingen = TreeMultimap.create(Ordering.arbitrary(), Ordering.natural());
        Multimap<Persoon, Opdracht> persoonToOpdrachten = HashMultimap.create();
        for (RekenHoofd hoofd : result) {
            Opdracht opdracht = hoofd.getOpdracht();
            Persoon persoon = opdracht.getPersoon();
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                AardKodeExtensie loonCode = lijn.getAardKodeExtensie();
                if (loonCode.isEindejaarsToelage()) {
                    persoonToJaarVergoedingen.put(persoon, "EJT");
                    persoonToOpdrachten.put(persoon, opdracht);
                } else if (loonCode.getIsVakantiegeld()) {
                    persoonToJaarVergoedingen.put(persoon, "VKG");
                    persoonToOpdrachten.put(persoon, opdracht);
                } else if (LoonCodeTools.isPremieBijzondereBeroepsbekwaamheid(loonCode)) {
                    persoonToJaarVergoedingen.put(persoon, "BBK");
                    persoonToOpdrachten.put(persoon, opdracht);
                } else if (LoonCodeTools.isPremieBijzondereBeroepstitel(loonCode)) {
                    persoonToJaarVergoedingen.put(persoon, "BBT");
                    persoonToOpdrachten.put(persoon, opdracht);
                } else if (LoonCodeTools.isAttractiviteitsPremie(loonCode)) {
                    persoonToJaarVergoedingen.put(persoon, "ATTRACT");
                    persoonToOpdrachten.put(persoon, opdracht);
                }
            }
        }
        List<RmControleLijstItem> lijst = new ArrayList<>();
        for (Persoon persoon : persoonToJaarVergoedingen.keySet()) {
            Collection<String> jaarVergoedingen = persoonToJaarVergoedingen.get(persoon);
            String opmerking = String.join(",", jaarVergoedingen);
            String opdrachtNrs = persoonToOpdrachten.get(persoon).stream().map(Opdracht::getOpdrachtnr).sorted().map(Number::toString)
                    .collect(Collectors.joining(","));
            lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdrachtNrs, RmControlelijstType.JAARVERGOEDINGEN, "", getNaam(persoon),
                    opmerking));
        }
        return lijst;
    }

    private List<RmControleLijstItem> controlesBlo(
            List<RekenHoofd> result, LoonBeslagData loonBeslagData) {
        MoneyMap<OpdrachtDatumSnrKey> onderhoudsgeldNettoMap = new HashMoneyMap<>();
        MoneyMap<OpdrachtDatumSnrKey> beslagOpLoonNettoMap = new HashMoneyMap<>();

        for (RekenHoofd hoofd : result) {
            Opdracht opdracht = hoofd.getOpdracht();
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                if (lijn.getAardKodeExtensie().behoortTotGroep(BESLAG_OP_LOON_KEY)) {
                    for (RekenBedrag rekenBedrag : lijn.getRekenBedragen()) {
                        if (rekenBedrag.getBedragType() == RekenBedragType.NETTO) {
                            if (lijn.getAardKodeExtensie().getCode() == BerekenBeslagOpLoon.ONDERHOUDSGELD_BLO_CODE) {
                                onderhoudsgeldNettoMap.addToMoney(new OpdrachtDatumSnrKey(opdracht, hoofd.getBeginDatum(), hoofd.getRnummer()),
                                        rekenBedrag.getBedrag());
                            } else if (lijn.getAardKodeExtensie().getCode() == BerekenBeslagOpLoon.BESLAG_OP_LOON_CODE) {
                                beslagOpLoonNettoMap.addToMoney(new OpdrachtDatumSnrKey(opdracht, hoofd.getBeginDatum(), hoofd.getRnummer()),
                                        rekenBedrag.getBedrag());
                            }
                        }
                    }
                }
            }
        }
        Set<Persoon> heeftOnderhoudsgeld = new HashSet<>();
        Set<Persoon> heeftBeslagOpLoon = new HashSet<>();
        Set<OpdrachtDatumSnrKey> keys = new HashSet<>(onderhoudsgeldNettoMap.keySet());
        keys.addAll(beslagOpLoonNettoMap.keySet());
        List<RmControleLijstItem> lijst = new ArrayList<>();
        for (OpdrachtDatumSnrKey key : keys) {
            Money onderhoudsgeld = onderhoudsgeldNettoMap.getMoney(key);
            Opdracht opdracht = key.getOpdracht();
            Persoon persoon = opdracht.getPersoon();
            if (onderhoudsgeld.signum() != 0) {
                lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdracht.getOpdrachtnr().toString(), RmControlelijstType.BESLAG_OP_LOON,
                        "Onderhoudsgeld " + key.getDatum().toString("MMMM yyyy", new Locale("nl", "BE")) + " snr:" + key.getSnummer(), getNaam(persoon),
                        onderhoudsgeld.negate().toString()));
                heeftOnderhoudsgeld.add(persoon);
            }
            Money beslagOpLoon = beslagOpLoonNettoMap.getMoney(key);
            if (beslagOpLoon.signum() != 0) {
                lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdracht.getOpdrachtnr().toString(), RmControlelijstType.BESLAG_OP_LOON,
                        "Beslag op loon " + key.getDatum().toString("MMMM yyyy", new Locale("nl", "BE")) + " snr:" + key.getSnummer(), getNaam(persoon),
                        beslagOpLoon.negate().toString()));
                heeftBeslagOpLoon.add(persoon);
            }
        }

        //Indien er loonbeslag gedefinieerd is op de uitvoeringsdatum van het b-nummer in corehr
        // maar er geen loonbeslag aanwezig is in het bnummer moet er een nul-lijn in de controle lijst komen zie LPBUNI-16626
        Set<Persoon> allePersonen =
                result.stream().map(RekenHoofd::getOpdracht).map(Opdracht::getPersoon).collect(Collectors.toSet());
        for (Persoon persoon : allePersonen) {
            String opdrachtNrs = persoon.getOpdrachten().stream().map(Opdracht::getOpdrachtnr).sorted().map(Number::toString)
                    .collect(Collectors.joining(","));
            if (!loonBeslagData.ohgLoonMap.get(persoon).isEmpty() && !heeftOnderhoudsgeld.contains(persoon)) {
                lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdrachtNrs, RmControlelijstType.BESLAG_OP_LOON,
                        "Onderhoudsgeld", getNaam(persoon),
                        Money.ZERO.toString()));
            }

            if (!loonBeslagData.beslagOpLoonMap.get(persoon).isEmpty() && !heeftBeslagOpLoon.contains(persoon)) {
                lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdrachtNrs, RmControlelijstType.BESLAG_OP_LOON,
                        "Beslag op loon", getNaam(persoon),
                        Money.ZERO.toString()));
            }

        }

        return lijst;
    }

    private static final Money GRENS_BRUTO_CONTROLE = new Money("8000");
    private static final Money GRENS_NETTO_CONTROLE = new Money("4000");

    private List<RmControleLijstItem> controlesOpBrutoNetto(List<RekenHoofd> result) {
        SortedSetMultimap<Persoon, LocalDate> persoonDatumsNettoMap = TreeMultimap.create(Comparator.comparing(Persoon::getId), Ordering.natural());
        MoneyMap<Persoon> persoonNettoMap = new HashMoneyMap<>();
        MoneyMap<PersoonDatumKey> persoonBrutoMap = new HashMoneyMap<>();
        MoneyMap<OpdrachtDatumKey> opdrachtBrutoMap = new HashMoneyMap<>();

        for (RekenHoofd hoofd : result) {
            Opdracht opdracht = hoofd.getOpdracht();
            Persoon persoon = opdracht.getPersoon();
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                for (RekenBedrag rekenBedrag : lijn.getRekenBedragen()) {
                    if (rekenBedrag.getBedragType() == RekenBedragType.NETTO && lijn.getReferentieJaar() == null) {
                        persoonNettoMap.addToMoney(persoon, rekenBedrag.getBedrag());
                        persoonDatumsNettoMap.put(persoon, hoofd.getBeginDatum());
                    } else if (rekenBedrag.getBedragType() == RekenBedragType.BRUTO_MAANDLOON) {
                        persoonBrutoMap.addToMoney(new PersoonDatumKey(persoon, hoofd.getBeginDatum()), rekenBedrag.getBedrag());
                        opdrachtBrutoMap.addToMoney(new OpdrachtDatumKey(opdracht, hoofd.getBeginDatum()), rekenBedrag.getBedrag());
                    }
                }
            }
        }
        Set<Persoon> personen = new HashSet<>(persoonNettoMap.keySet());
        List<RmControleLijstItem> lijst = new ArrayList<>();
        for (Persoon persoon : personen) {
            Money totaalNetto = persoonNettoMap.getMoney(persoon);
            if (totaalNetto.compareTo(GRENS_NETTO_CONTROLE) > 0) {
                String opdrachtNrs =
                        persoon.getOpdrachten().stream().map(Opdracht::getOpdrachtnr).sorted().map(Number::toString).collect(Collectors.joining(","));
                Set<LocalDate> datums = persoonDatumsNettoMap.get(persoon);
                String datumsString = datums.stream().map(x -> x.toString("MMMM yyyy", new Locale("nl", "BE"))).collect(Collectors.joining(","));
                lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdrachtNrs, RmControlelijstType.NETTO_GROTER_DAN_BOVENGRENS,
                        "Groter dan " + GRENS_NETTO_CONTROLE + " " + datumsString, getNaam(persoon), totaalNetto.toString()));
            }
        }

        for (PersoonDatumKey key : persoonBrutoMap.keySet()) {
            Money totaalBruto = persoonBrutoMap.getMoney(key);
            if (totaalBruto.compareTo(GRENS_BRUTO_CONTROLE) > 0) {
                Persoon persoon = key.getPersoon();
                for (Opdracht opdracht : persoon.getOpdrachten()) {
                    Money totaalBrutoOpdracht = opdrachtBrutoMap.getMoney(new OpdrachtDatumKey(opdracht, key.getDatum()));
                    lijst.add(new RmControleLijstItem(persoon.getPersoneelsNr(), opdracht.getOpdrachtnr().toString(),
                            RmControlelijstType.BRUTO_GROTER_DAN_BOVENGRENS,
                            "Groter dan " + GRENS_BRUTO_CONTROLE + "; " + key.getDatum().toString("MMMM yyyy", new Locale("nl", "BE")), getNaam(persoon),
                            totaalBrutoOpdracht.toString()));
                }
            }
        }
        return lijst;
    }

    private List<RekenHoofd> vindRekenResultatenMetBnr(Admin admin, Integer bNummer, List<Integer> opdrachtIdList) {
        List<SNummerStaat> snrStaten = snummerStaatService.findByBNumber(admin, bNummer);
        Set<Integer> snrs = snrStaten.stream().map(SNummerStaat::getSnummer).collect(Collectors.toSet());

        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch("rekenLijnen{rekenBedragen}");
        cb.and("rnummer", Criterium.IN(snrs));
        if (!opdrachtIdList.isEmpty()) {
            cb.and("opdracht.id", Criterium.IN(opdrachtIdList));
        }
        List<RekenHoofd> result = rekenResultatenService.findByCriteria(admin, cb);

        List<Opdracht> opdrachten = vindGebruikteOpdrachten(admin, result);
        Map<Integer, Opdracht> idToOpdrachtMap = AlgemeenTools.maakIdToIdentifiableMap(opdrachten);
        result.forEach(x -> x.setOpdracht(idToOpdrachtMap.get(x.getOpdracht().getId())));

        List<AardKodeExtensie> loonCodes = vindGebruikteLoonCodes(result);
        Map<Integer, AardKodeExtensie> idToLoonCodeMap = AlgemeenTools.maakIdToIdentifiableMap(loonCodes);
        result.stream().map(RekenHoofd::getRekenLijnen).flatMap(Set::stream)
                .forEach(x -> x.setAardKodeExtensie(idToLoonCodeMap.get(x.getAardKodeExtensie().getId())));

        return result;
    }

    private List<AardKodeExtensie> vindGebruikteLoonCodes(List<RekenHoofd> rekenResultaten) {
        List<Integer> akeIds = rekenResultaten.stream().map(RekenHoofd::getRekenLijnen).flatMap(Set::stream).map(RekenLijn::getAardKodeExtensie)
                .map(AardKodeExtensie::getId).collect(Collectors.toList());
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("id", Criterium.IN(akeIds));
        cb.fetch("groepen");
        return aardKodeExtensieFacade.findByIds(akeIds);
    }

    private List<Opdracht> vindGebruikteOpdrachten(Admin admin, Collection<RekenHoofd> rekenResultaten) {
        TemporalContext.getInstance().setActualInterval(new Eternity());
        Set<Integer> opdrachtIds = rekenResultaten.stream().map(RekenHoofd::getOpdracht).map(Opdracht::getId).collect(Collectors.toSet());
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch("opdrachtSlices, persoon{persoonSlices}");
        cb.and("id", Criterium.IN(opdrachtIds));

        List<Opdracht> opdrachten = opdrachtService.findByCriteria(admin, cb);
        TemporalContext.getInstance().clearActualInterval();
        opdrachten.forEach(x -> x.getPersoon().setOpdrachten(new HashSet<>()));
        opdrachten.forEach(x -> x.getPersoon().getOpdrachten().add(x));
        return opdrachten;
    }

    private String getNaam(Persoon persoon) {
        return persoon.getFamilienaam().trim() + " " + persoon.getVoornaam().trim();
    }

    private LoonBeslagData bouwLoonBeslagData(Admin admin, List<RekenHoofd> result) {

        Set<Persoon> personen = result.stream().map(RekenHoofd::getOpdracht).map(Opdracht::getPersoon).collect(Collectors.toSet());

        Set<LocalDate> beslagDatums = result.stream().map(RekenHoofd::getBeslagDatum).collect(Collectors.toSet());
        LoonBeslagData loonBeslagData = new LoonBeslagData();
        for (Persoon persoon : personen) {
            List<HrWageGarnishment> garnishes = getBeslagOpLoonDefinitiesCoreHr(admin, persoon);
            for (LocalDate beslagDatum : beslagDatums) {
                List<HrWageGarnishment> validGarnishes =
                        garnishes.stream().filter(g -> isDateValid(g, beslagDatum)).toList();
                for (HrWageGarnishment garnish : validGarnishes) {
                    int code = garnish.getSlice().getKind().getCode();
                    if (code == BerekenBeslagOpLoon.BESLAG_OP_LOON_CODE) {
                        loonBeslagData.beslagOpLoonMap.put(persoon, garnish);
                    } else if (code == BerekenBeslagOpLoon.ONDERHOUDSGELD_BLO_CODE) {
                        loonBeslagData.ohgLoonMap.put(persoon, garnish);
                    }
                }
            }
        }
        return loonBeslagData;
    }

    private boolean isDateValid(HrWageGarnishment g, LocalDate datum) {
        return !g.getBegindatum().isAfter(datum) && (g.getEinddatum() == null || !g.getEinddatum().isBefore(datum));
    }

    private static class LoonBeslagData {
        Multimap<Persoon, HrWageGarnishment> beslagOpLoonMap = HashMultimap.create();
        Multimap<Persoon, HrWageGarnishment> ohgLoonMap = HashMultimap.create();
    }


    private List<HrWageGarnishment> getBeslagOpLoonDefinitiesCoreHr(Admin admin, Persoon persoon) {
        Clustermapping clusterMapping = clusterMappingService.getByAdmin(admin);
        Cluster cluster = null;
        if (clusterMapping != null) {
            cluster = clusterService.getById(clusterMapping.getClusterId());
        }
        List<HrWageGarnishment> garnishes;
        if (cluster != null) {
            garnishes =
                    hrWageGarnishmentService.findByAdminPersoon(cluster, admin, persoon);
        } else {
            garnishes = new ArrayList<>();
        }

        return garnishes;
    }
}
